sql:
SELECT demand_kw, solar_capacity_factor, wind_capacity_factor
FROM energy_data
WHERE time_hr >= 1000 AND time_hr <= 2000;

SELECT demand_kw
FROM energy_data
WHERE time_hr = 5;

SELECT AVG(energy_data.demand_kw - demand_forecast.forecasted_demand_kw) AS avg_demand_forecast_error
FROM energy_data
LEFT JOIN demand_forecast ON energy_data.time_hr = demand_forecast.time_hr;

SELECT source_name, capacity_kw, status
FROM energy_sources
WHERE status <> 'active' AND capacity_kw > (SELECT AVG(capacity_kw) FROM energy_sources);

SELECT SUM(capacity_wh) AS total_storage_capacity
FROM energy_storage
WHERE type = 'Battery';

SELECT AVG(demand_kw) AS average_demand_kw, AVG(temperature_c) AS average_temperature_c
FROM energy_data
WHERE time_hr BETWEEN 9 AND 15 AND temperature_c > 25;

SELECT energy_data.demand_kw
FROM energy_data
INNER JOIN demand_forecast ON energy_data.time_hr = demand_forecast.time_hr;

SELECT SUM(curtailment_solar_kw) AS total_solar_curtailment
FROM energy_data
WHERE time_hr >= (
    SELECT MAX(time_hr) - 24
    FROM energy_data
);

external_knowledge:
- 'Whispers beyond the dawn' metaphorically refers to wind speeds recorded after the time has passed midnight (time_hr > 0).;
- 'First breeze' implies the query's `LIMIT 1`, indicating we are interested in the first instance of the condition being met.;
- 'Guardian named 'operator'' refers to a user in the system with the username 'operator', ensuring there is a presence or condition check for this user's existence.

sql:
SELECT AVG(forecasted_demand_kw) AS Average_Demand_24hr
FROM demand_forecast
WHERE time_hr BETWEEN 0 AND 23;

SELECT time_hr, temperature_c, humidity
FROM weather_forecast
WHERE forecast_id = 1;

SELECT MAX(temperature_c) AS MaxTemperature
FROM weather_forecast
WHERE time_hr >= 2880 AND time_hr < 3600;

external_knowledge:
- Shadows: Users with no energy data;
- Lantern bearers: Users with the role of 'Operator';
- Vast darkness: The metaphorical representation of the scenario where data is missing or incomplete.
